class RhoovaConfig{

    constructor(apiKey, apiSecret, apiURL){
        this.setApiKey(apiKey);
        this.setApiSecret(apiSecret);
        this.setApiUrl(apiURL);
    }

    getApiKey(){
        return this.apiKey;
    }

    setApiKey(apiKey){
        this.apiKey = apiKey;
    }

    getApiSecret(){
        return this.apiSecret;
    }

    setApiSecret(apiSecret){
        this.apiSecret = apiSecret;
    }

    getApiUrl(){
        return this.apiUrl;
    }

    setApiUrl(apiUrl){
        this.apiUrl = apiUrl;
    }
}

module.exports = RhoovaConfig;
